      "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 4,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description:
      "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 5,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description:
      "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 6,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description:
      "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
  // Add more articles here
];

const AllNews = () => {
    useEffect(() => {
      // Check if there's a saved scroll position in sessionStorage
      const savedPosition = sessionStorage.getItem("scrollPosition");
      if (savedPosition) {
        window.scrollTo(0, savedPosition); // Restore scroll position
      }
  
      // Save scroll position when leaving the page
      return () => {
        sessionStorage.setItem("scrollPosition", window.scrollY); // Save scroll position
      };
    }, []);
  
    return (
      <div className="AllNews">
        <div className="back-button-container">
          <Link to="/news" className="back-button">
            ← Back to News
          </Link>
        </div>
  
        <h2>All News</h2>
        <div className="news-container">
          {articles.map((article) => (
            <div className="news-card" key={article.id}>
              <img
                src={article.image}
                alt={article.title}
                className="news-image"
              />
              <div className="news-content">
                <h3>{article.title}</h3>
                <p className="news-date">📅 {article.date}</p>
                <p className="news-description">{article.description}</p>
                <div className="button-container">
                  <button className="news-button">Read More</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };
  
  export default AllNews;
